#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        for (int i = 1; i <= N; ++i) {
            int val = (i % 2 ? 1 : 2);
            printf("%d", val);
            if (i < N) printf(" ");
        }
        if (T) printf("\n");
    }
    return 0;
}

